from __future__ import annotations
import json
import os
import re
import time
import logging
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from functools import wraps
from typing import Any, Callable, Optional
from datetime import datetime, timedelta

log = logging.getLogger(__name__)


# ── Tool result helpers ────────────────────────────────────────────────────────

def success(data: Any, **extras) -> str:
    return json.dumps({'success': True, 'data': data, **extras})

def failure(error_code: str, message: str, suggestion: str = '') -> str:
    return json.dumps({'success': False, 'error_code': error_code, 'message': message, 'suggestion': suggestion})


# ── Rate limiter ───────────────────────────────────────────────────────────────

class RateLimiter:
    def __init__(self, max_calls: int, window_seconds: int = 60):
        self.max_calls = max_calls
        self.window = timedelta(seconds=window_seconds)
        self._calls: list[datetime] = []

    def check(self) -> bool:
        now = datetime.utcnow()
        self._calls = [t for t in self._calls if now - t < self.window]
        if len(self._calls) >= self.max_calls:
            return False
        self._calls.append(now)
        return True


# ── Base tool with built-in safety ────────────────────────────────────────────

class SafeTool(ABC):
    rate_limit: int = 100  # calls per minute

    def __init__(self):
        self._limiter = RateLimiter(self.rate_limit)
        self._call_count = 0
        self._error_count = 0

    @property
    @abstractmethod
    def name(self) -> str: ...

    @property
    @abstractmethod
    def description(self) -> str: ...

    @property
    @abstractmethod
    def schema(self) -> dict: ...

    @abstractmethod
    def _execute(self, **kwargs) -> str: ...

    def execute(self, **kwargs) -> str:
        if not self._limiter.check():
            return failure('RATE_LIMIT', f'Tool {self.name} rate limit exceeded ({self.rate_limit}/min)', 'Wait 60 seconds before retrying')
        self._call_count += 1
        try:
            log.info('Tool call: %s(%s)', self.name, {k: str(v)[:50] for k, v in kwargs.items()})
            result = self._execute(**kwargs)
            return result
        except Exception as e:
            self._error_count += 1
            log.error('Tool error: %s: %s', self.name, e)
            return failure('INTERNAL_ERROR', str(e), 'Check your inputs and try again')

    def to_openai_spec(self) -> dict:
        return {'type': 'function', 'function': {'name': self.name, 'description': self.description, 'parameters': self.schema}}

    @property
    def stats(self) -> dict:
        return {'calls': self._call_count, 'errors': self._error_count, 'error_rate': f'{self._error_count/max(1,self._call_count):.1%}'}


# ── Concrete tools ─────────────────────────────────────────────────────────────

class DatabaseQueryTool(SafeTool):
    rate_limit = 60
    name = 'query_database'
    description = (
        'Query the product and order database. Returns structured records. '
        'Use for: product details, order history, inventory levels. '
        'Do NOT use for: user authentication, financial transactions.'
    )
    schema = {
        'type': 'object',
        'properties': {
            'table': {
                'type': 'string',
                'enum': ['products', 'orders', 'customers'],
                'description': 'Database table to query',
            },
            'filter': {
                'type': 'object',
                'description': 'Key-value pairs to filter records, e.g. {"status": "shipped"}',
            },
            'limit': {
                'type': 'integer',
                'minimum': 1, 'maximum': 50,
                'description': 'Maximum records to return (default: 10)',
            },
        },
        'required': ['table'],
    }

    # Simulated DB
    _DB = {
        'products': [
            {'id': 'P001', 'name': 'Widget Pro', 'price': 29.99, 'stock': 150, 'category': 'hardware'},
            {'id': 'P002', 'name': 'Gadget Plus', 'price': 49.99, 'stock': 0, 'category': 'electronics'},
            {'id': 'P003', 'name': 'Tool Deluxe', 'price': 99.99, 'stock': 42, 'category': 'equipment'},
        ],
        'orders': [
            {'id': 'ORD-001', 'customer_id': 'C001', 'total': 89.97, 'status': 'shipped', 'product_ids': ['P001', 'P003']},
            {'id': 'ORD-002', 'customer_id': 'C002', 'total': 49.99, 'status': 'pending', 'product_ids': ['P002']},
        ],
        'customers': [
            {'id': 'C001', 'name': 'Alice Johnson', 'email': 'alice@example.com', 'tier': 'gold'},
            {'id': 'C002', 'name': 'Bob Smith', 'email': 'bob@example.com', 'tier': 'standard'},
        ],
    }

    def _execute(self, table: str, filter: Optional[dict] = None, limit: int = 10) -> str:
        rows = self._DB.get(table, [])
        if not rows:
            return failure('TABLE_EMPTY', f'Table {table} has no records')

        if filter:
            rows = [r for r in rows if all(str(r.get(k, '')).lower() == str(v).lower() for k, v in filter.items())]

        rows = rows[:limit]
        if not rows:
            return failure('NO_RESULTS', f'No records in {table} match filter {filter}', 'Try different filter values or remove filters')

        return success({'table': table, 'records': rows, 'count': len(rows)})


class EmailDraftTool(SafeTool):
    """Creates email drafts — NEVER sends automatically."""
    rate_limit = 20
    name = 'draft_email'
    description = (
        'Draft an email. Returns a preview for human review. '
        'NEVER sends automatically — a human must approve and send. '
        'Use for: customer communications, support responses, notifications.'
    )
    schema = {
        'type': 'object',
        'properties': {
            'to': {'type': 'string', 'description': 'Recipient email address'},
            'subject': {'type': 'string', 'description': 'Email subject line'},
            'body': {'type': 'string', 'description': 'Email body content (plain text or markdown)'},
            'priority': {'type': 'string', 'enum': ['normal', 'high'], 'description': 'Email priority'},
        },
        'required': ['to', 'subject', 'body'],
    }

    def _execute(self, to: str, subject: str, body: str, priority: str = 'normal') -> str:
        # Validate email format
        if not re.match(r'^[\w.+-]+@[\w-]+\.[\w.]+$', to):
            return failure('INVALID_EMAIL', f'Invalid email address: {to}', 'Use format: user@domain.com')

        draft = {
            'draft_id': f'draft_{int(time.time())}',
            'to': to,
            'subject': subject,
            'body': body,
            'priority': priority,
            'status': 'DRAFT — awaiting human approval',
            'created_at': datetime.utcnow().isoformat(),
        }
        log.warning('EMAIL DRAFT CREATED — requires human review: to=%s subject=%s', to, subject)
        return success(draft, message='Draft created. Human review required before sending.')


class CodeExecutionTool(SafeTool):
    rate_limit = 30
    name = 'run_python'
    description = (
        'Execute Python code in a sandboxed environment. '
        'Returns stdout output or error. '
        'Available builtins: print, range, len, sum, sorted, max, min, abs, round, enumerate, zip, list, dict, set, str, int, float. '
        'No file system, network, or import access.'
    )
    schema = {
        'type': 'object',
        'properties': {
            'code': {'type': 'string', 'description': 'Python code to execute'},
            'timeout_seconds': {'type': 'integer', 'minimum': 1, 'maximum': 30, 'description': 'Execution timeout (default: 10)'},
        },
        'required': ['code'],
    }

    SAFE_BUILTINS = {
        'print': print, 'range': range, 'len': len, 'sum': sum,
        'sorted': sorted, 'max': max, 'min': min, 'abs': abs,
        'round': round, 'enumerate': enumerate, 'zip': zip,
        'list': list, 'dict': dict, 'set': set,
        'str': str, 'int': int, 'float': float, 'bool': bool,
        '__builtins__': {},
    }

    def _execute(self, code: str, timeout_seconds: int = 10) -> str:
        import io
        import contextlib
        import signal

        # Block dangerous patterns
        blocked = ['import ', '__import__', 'open(', 'os.', 'subprocess', 'exec(', 'eval(']
        for pattern in blocked:
            if pattern in code:
                return failure('UNSAFE_CODE', f'Code contains blocked pattern: {pattern}', 'Only pure computation is allowed — no imports or system calls')

        stdout = io.StringIO()
        try:
            with contextlib.redirect_stdout(stdout):
                exec(code, self.SAFE_BUILTINS.copy())  # noqa: S102
            output = stdout.getvalue()
            return success({'output': output or '(no output)', 'lines': output.count('\n') + 1 if output else 0})
        except SyntaxError as e:
            return failure('SYNTAX_ERROR', f'Syntax error: {e}', 'Check your Python syntax')
        except Exception as e:
            return failure('RUNTIME_ERROR', f'{type(e).__name__}: {e}', 'Review the code logic')


# ── Compound tool: wraps multiple tools ───────────────────────────────────────

class OrderLookupTool(SafeTool):
    """Compound tool: looks up order AND related customer and product info."""
    rate_limit = 30
    name = 'get_order_details'
    description = (
        'Get full order details including customer info and product list. '
        'Use when you need complete order context — saves multiple separate tool calls.'
    )
    schema = {
        'type': 'object',
        'properties': {
            'order_id': {'type': 'string', 'description': 'Order ID, e.g. "ORD-001"'},
        },
        'required': ['order_id'],
    }

    def __init__(self):
        super().__init__()
        self._db = DatabaseQueryTool()

    def _execute(self, order_id: str) -> str:
        # Fetch order
        order_result = json.loads(self._db.execute(table='orders', filter={'id': order_id}))
        if not order_result['success']:
            return failure('ORDER_NOT_FOUND', f'Order {order_id} not found', 'Check the order ID format: ORD-XXX')

        order = order_result['data']['records'][0]

        # Fetch customer
        cust_result = json.loads(self._db.execute(table='customers', filter={'id': order['customer_id']}))
        customer = cust_result['data']['records'][0] if cust_result['success'] else {'name': 'Unknown'}

        # Fetch products
        products = []
        for pid in order.get('product_ids', []):
            prod_result = json.loads(self._db.execute(table='products', filter={'id': pid}))
            if prod_result['success']:
                products.extend(prod_result['data']['records'])

        return success({
            'order': order,
            'customer': customer,
            'products': products,
        })


